@shared_task(bind=True, acks_late=True)
def send_order_confirmation(self, order_id: int) -> None:
    order = Order.objects.filter(pk=order_id).first()
    if order is None:
        log.warning("order %s missing; skipping", order_id)
        return
    if order.confirmation_sent_at is not None:
        return  # already sent
    send_email(to=order.email, template="order_confirmation")
    with transaction.atomic():
        Order.objects.filter(pk=order.pk, confirmation_sent_at__isnull=True).update(
            confirmation_sent_at=timezone.now()
        )

from celery import shared_task from celery.utils.log import get_task_logger
log = get_task_logger(__name__)
@shared_task( name="orders.process_order", bind=True, max_retries=3, autoretry_for=(ConnectionError, TimeoutError), retry_backoff=True, retry_backoff_max=600, retry_jitter=True, soft_time_limit=300, time_limit=360, acks_late=True, ) def process_order(self, order_id: int) -> dict: from apps.orders.models import Order
order = Order.objects.filter(pk=order_id).first() if order is None: log.warning("order %s not found; skipping", order_id) return {"status": "skipped", "reason": "not_found"}
# business logic log.info("processed order %s", order_id) return {"status": "success", "order_id": order_id}

@shared_task(bind=True, soft_time_limit=1800)
def sync_customers(self, full_sync: bool = False) -> dict:
    customers = get_all_customers() if full_sync else get_recent_customers()
    total = len(customers)
    for idx, c in enumerate(customers):
        process_customer(c)
        if idx % 100 == 0:
            self.update_state(
                state="PROGRESS",
                meta={"current": idx, "total": total,
                      "percent": int(idx / total * 100)},
            )
    return {"status": "completed", "total": total}

@shared_task(
    name="notifications.send_welcome_email",
    bind=True,
    autoretry_for=(Exception,),
    retry_backoff=True,
    max_retries=5,
    acks_late=True,
)
def send_welcome_email(self, user_id: int) -> dict:
    from apps.users.models import User

    user = User.objects.filter(pk=user_id).first()
    if user is None:
        return {"status": "skipped", "reason": "user_not_found"}
    if user.welcome_email_sent:
        return {"status": "skipped", "reason": "already_sent"}

    send_mail(
        subject="Welcome!",
        message="...",
        from_email=settings.DEFAULT_FROM_EMAIL,
        recipient_list=[user.email],
    )
    User.objects.filter(pk=user_id, welcome_email_sent=False).update(
        welcome_email_sent=True
    )
    return {"status": "sent"}
